 if o['relationship']=='addresses' and o['target_id'].startswith('ResearchTopic:'): rels[o['target_id']]+=1
 if o['relationship']=='uses' and o['target_id'].startswith('MethodologicalConcept:'): srcs[o['target_id']]+=1
